contract cons &#123;    address public constant addr = 0x777788889999AaAAbBbbCcccddDdeeeEfFFfCcCc;    function tryToChange() public &#123;        //addr = 0x777788889999AaAAbBbbCcccddDdeeeEfFFfCcCc;//error    &#125;&#125;

immutableimmutable修饰的变量不需要初始化，同样不可以被修改但必须在构造函数中进行初始化
pragma solidity ^0.8.17;//SPDX-License-Identifier: MITcontract immu &#123;    address private immutable immu1 ;    uint private immutable myUInt;    constructor(uint uI) &#123;        immu1 = msg.sender;        myUInt = uI;    &#125;&#125;

getter方法必须声明为view//SPDX-License-Identifier:MITpragma solidity ^0.8.17;contract stateV &#123;    uint public num;    function get() public view returns(uint)&#123;        return num;    &#125;    function set(uint n) public &#123;        num = n;    &#125;&#125;
gas 与 gas limitpragma solidity ^0.8.17;//SPDX-License-Identifier: MITcontract gasAbout &#123;    int public i = 0;    // 花光准备的gas会导致交易失败    // 状态改变会回退    // gas不会退款    function g() public &#123;        //循环到花光所限制的gas，交易失败，i不会发生改变        while(true) &#123;            ++i;        &#125;    &#125;&#125;

参考-&gt;Gas
GasHow much ether do you need to pay for a transaction?You pay gas spent * gas price amount of ether, where

gas is a unit of computation
gas spent is the total amount of gas used in a transaction
gas price is how much ether you are willing to pay per gas

Transactions with higher gas price have higher priority to be included in a block.
Unspent gas will be refunded.
Gas LimitThere are 2 upper bounds to the amount of gas you can spend

gas limit (max amount of gas you’re willing to use for your transaction, set by you)

block gas limit (max amount of gas allowed in a block, set by the network)


试着依靠自己的理解，翻译一下：
Gas一个交易需要支付多少？我们需要支付的以太币为 `Gas花费数量`*`Gas单价`，其中：- Gas是计算单位- Gas Spent是一个交易中花费的Gas数- Gas Price是你愿意为每个Gas支付的价格在区块中，更高的Gas单价具有更高的优先级多出的Gas会被退回Gas Limit对于我们花费gas的总数有两个上限- Gas Limit（自己设置的愿意交易Gas花费最大`数量`限额）- Block Gas Limit（网络设置的区块Gas花费最大`数量`限额）

