数组简单例子pragma solidity ^0.8.17;//SPDX-License-Identifier: UNLICENSEDcontract Array &#123;    uint[] public arr ;    uint[] public arr2 = [1, 2, 3];    uint[10] public arr3;    function get(uint i) public view returns (uint)&#123;        return arr[i];    &#125;    function getArr() public view returns (uint[] memory) &#123;        return arr;    &#125;    function push(uint i) public &#123;        arr.push(i);    &#125;    function pop()public &#123;    //pop会相应减少长度        arr.pop();    &#125;    function getLength() public view returns(uint)&#123;        return arr.length;    &#125;    function remove(uint index) public &#123;    //delete只删除相应索引上的值        delete arr[index];    &#125;    function examples() external &#123;        uint[] memory a = new uint[](5);//只能生成固定长度    &#125;    &#125;

删除元素与Java不同的是，solidity没有现成方法来调用进行删除某一索引上的元素，比如自行定义函数
方法一（能保留原有顺序）：pragma solidity ^0.8.17;// SPDX-License-Identifier: MITcontract arrShift1 &#123;uint[] public arr;function remove(uint _index) public &#123;require(_index &lt; arr.length, &quot;index out of bound&quot;);for(uint i = _index; i &lt; arr.length-1; i++) &#123;arr[i] = arr[i+1];&#125;arr.pop();//自要删除的元素起，后面每一元素覆盖前面，然后删除最后的值&#125;function test() external &#123;arr = [1,2,3,4,5];remove(2);assert(arr[0] == 1);assert(arr[1] == 2);assert(arr[2] == 4);assert(arr[3] == 5);assert(arr.length == 4);        arr = [1];        remove(0);        assert(arr.length == 0);    &#125;&#125;
方法二（简单粗暴，直接替换）：pragma solidity ^0.8.17;//SPDX-License-Identifier:mitcontract arrReplace &#123;    uint[] public arr;    function arrRepl(uint _index) public &#123;        arr[_index] = arr[arr.length-1];        arr.pop();    &#125;    function test() public&#123;        arr = [1,2,3,4,5];        arrRepl(2);        assert(arr[0]==1);        assert(arr[1]==2);        assert(arr[2]==5);        assert(arr[3]==4);        assert(arr.length==4);    &#125;&#125;
